// ── Data generators ───────────────────────────────────────────────────────────
const buildFoodDiary = (clientId) => {
  const diary = {};
  DAYS.forEach((d,di) => {
    diary[d] = {};
    MEALS.forEach(m => {
      const pool = FOODS[m];
      const count = m === "Snack" ? 1 : 2 + (di % 2);
      diary[d][m] = Array.from({length:count}, (_,i) => ({
        ...pool[(clientId * (di+1) * (i+3) + di * 7) % pool.length],
        id:`${clientId}-${d}-${m}-${i}`,
        flagged:false,
        coachNote:"",
      }));
    });
    if(di === 5 || (clientId === 3 && di > 3)) diary[d]["Snack"] = [];
  });
  return diary;
};

const buildMoodLog = (clientId) => {
  const bases = {1:[4,5,3,4,4,5,4],2:[5,5,4,5,4,3,5],3:[3,2,3,3,2,3,3],4:[5,5,5,4,5,5,5],5:[4,3,4,4,3,4,4]};
  const notes = {
    1:["","Energy great post swim","Carbs felt low","Strong brick session","","Nailed long run",""],
    2:["Squat PR today! 🎉","","Bench felt heavy","","Back feeling tight","","Deadlift session solid"],
    3:["Hard WOD","Really struggled today","Better energy","Appetite still low","Missed breakfast","",""],
    4:["","Perfect pool session","","Technique clicking","","Rest day – relaxed",""],
    5:["Easy 10k","Legs heavy","Tempo felt good","","Skipped afternoon run","Long run ✓",""],
  };
  const b = bases[clientId]||[4,4,3,4,4,3,4];
  const n = notes[clientId]||["","","","","","",""];
  return DAYS.reduce((acc,d,i)=>{
    const mood = MOODS[b[i]-1];
    acc[d] = {...mood, note:n[i], timestamp:new Date(Date.now()-(6-i)*86400000).toISOString()};
    return acc;
  },{});
};

const buildWeightHistory = (clientId) => {
  const bases  = {1:79.1,2:91.2,3:66.8,4:71.6,5:58.9};
  const trends = {1:-0.12,2:+0.15,3:-0.19,4:-0.09,5:-0.10};
  const base   = bases[clientId]||75, trend = trends[clientId]||-0.1;
  return Array.from({length:8},(_,i)=>{
    const jitter = ((clientId*i*7)%10-5)*0.06;
    const dt = new Date(Date.now()-((7-i)*7)*86400000);
    return {date:dt.toISOString().slice(0,10), label:`W${i+1}`, weight:parseFloat((base+trend*i+jitter).toFixed(1))};
  });
};

const buildTrainingLog = (clientId, sport) => {
  const types  = SESSION_TYPES[sport]||["Training","Rest"];
  const sData  = {
    1:{s:[1,2,3,0,1,3,4],r:[7,8,6,0,7,9,0],d:[70,90,60,0,80,120,0]},
    2:{s:[0,1,2,4,0,3,4],r:[8,7,9,0,8,7,0], d:[75,70,90,0,80,60,0]},
    3:{s:[0,1,2,0,1,4,4],r:[7,8,6,0,7,0,0], d:[55,60,45,0,50,0,0]},
    4:{s:[0,1,2,3,0,1,4],r:[7,8,7,8,0,7,0], d:[65,80,75,70,0,60,0]},
    5:{s:[0,1,2,0,3,1,4],r:[6,7,8,0,9,7,0], d:[45,55,70,0,90,75,0]},
  };
  const {s,r,d} = sData[clientId]||{s:[0,1,2,0,1,2,4],r:[7,7,7,0,7,7,0],d:[60,60,60,0,60,60,0]};
  return DAYS.map((day,i)=>({day,type:types[s[i]],rpe:r[i],duration:d[i],trained:types[s[i]]!=="Rest"}));
};

