const COACH_META = [
  {coachId:"sarah",name:"Sarah Mitchell",role:"Performance Coach",email:"sarah@norules.com",clientIds:[1,2,3],avatarColor:T.coachGreen},
  {coachId:"tom",  name:"Tom Hargreaves", role:"Strength Coach",   email:"tom@norules.com", clientIds:[4,5],  avatarColor:T.protein},
];

// ── Admin Dashboard ───────────────────────────────────────────────────────────
function AdminDashboard({allClients}){
  const [tab,setTab]=useState("overview");
  const totalClients=allClients.length;
  const avgAdh=Math.round(allClients.reduce((a,c)=>a+c.adherence,0)/totalClients);
  const onTrack=allClients.filter(c=>c.status==="on-track").length;
  const needsAttn=allClients.filter(c=>c.adherence<70||c.nextCheckIn<=1).length;
  const statusMeta={"on-track":{label:"ON TRACK",color:T.coachGreen},over:{label:"OVER",color:T.warn},under:{label:"UNDER",color:T.danger}};
  return (
    <div style={{display:"flex",flexDirection:"column",gap:22}}>
      {/* Admin banner */}
      <div style={{background:`linear-gradient(135deg,${T.accent}18,${T.coachGreen}12)`,border:`1px solid ${T.accent}40`,borderRadius:20,padding:"22px 28px",display:"flex",alignItems:"center",gap:18}}>
        <div style={{width:54,height:54,borderRadius:"50%",background:`${T.accent}25`,border:`2px solid ${T.accent}55`,display:"flex",alignItems:"center",justifyContent:"center",fontFamily:"Bebas Neue",fontSize:22,color:T.accent,flexShrink:0}}>E</div>
        <div style={{flex:1}}>
          <div style={{fontFamily:"Bebas Neue",fontSize:24,letterSpacing:2,color:T.text}}>ADMIN OVERVIEW · ESME</div>
          <div style={{fontFamily:"DM Sans",fontSize:12,color:T.muted,marginTop:3}}>Head Coach · Full roster visibility across all coaching staff</div>
        </div>
        <div style={{display:"flex",gap:8}}>
          {["overview","coaches","clients"].map(t=>(
            <button key={t} onClick={()=>setTab(t)} style={{background:tab===t?T.accent:"none",color:tab===t?T.bg:T.muted,border:`1px solid ${tab===t?T.accent:T.border}`,borderRadius:8,padding:"7px 16px",fontFamily:"Bebas Neue",fontSize:13,letterSpacing:1,cursor:"pointer",transition:"all .2s"}}>
              {t.toUpperCase()}
            </button>
          ))}
        </div>
      </div>

      {/* Stats row */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:12}}>
        <StatCard label="TOTAL ATHLETES" value={totalClients} color={T.accent}/>
        <StatCard label="AVG ADHERENCE" value={`${avgAdh}%`} color={T.coachGreen} sub={avgAdh>=80?"● Excellent":"● Needs Focus"}/>
        <StatCard label="ON TRACK" value={onTrack} color={T.coachGreen} unit={`of ${totalClients}`}/>
        <StatCard label="NEEDS ATTENTION" value={needsAttn} color={T.danger} sub={needsAttn>0?"● Review Today":"● All Good"}/>
      </div>

      {tab==="overview"&&(
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:16}}>
          {COACH_META.map(cm=>{
            const coachClients=allClients.filter(c=>cm.clientIds.includes(c.id));
            const ca=coachClients.length?Math.round(coachClients.reduce((a,c)=>a+c.adherence,0)/coachClients.length):0;
            const onT=coachClients.filter(c=>c.status==="on-track").length;
            const attn=coachClients.filter(c=>c.adherence<70||c.nextCheckIn<=1).length;
            return (
              <div key={cm.coachId} style={{background:T.card,border:`1px solid ${T.border}`,borderRadius:18,padding:22}}>
                <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:18}}>
                  <div style={{width:44,height:44,borderRadius:"50%",background:`${cm.avatarColor}25`,border:`2px solid ${cm.avatarColor}55`,display:"flex",alignItems:"center",justifyContent:"center",fontFamily:"Bebas Neue",fontSize:16,color:cm.avatarColor}}>
                    {cm.name.split(" ").map(n=>n[0]).join("")}
                  </div>
                  <div>
                    <div style={{fontFamily:"DM Sans",fontSize:14,fontWeight:600,color:T.text}}>{cm.name}</div>
                    <div style={{fontFamily:"JetBrains Mono",fontSize:10,color:T.muted}}>{cm.role} · {cm.email}</div>
                  </div>
                </div>
                <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:10,marginBottom:16}}>
                  <div style={{background:T.surface,borderRadius:12,padding:"12px 10px",textAlign:"center"}}>
                    <div style={{fontFamily:"Bebas Neue",fontSize:22,color:T.accent}}>{coachClients.length}</div>
                    <div style={{fontFamily:"DM Sans",fontSize:9,color:T.muted,letterSpacing:1}}>ATHLETES</div>
                  </div>
                  <div style={{background:T.surface,borderRadius:12,padding:"12px 10px",textAlign:"center"}}>
                    <div style={{fontFamily:"Bebas Neue",fontSize:22,color:ca>=80?T.coachGreen:ca>=65?T.warn:T.danger}}>{ca}%</div>
                    <div style={{fontFamily:"DM Sans",fontSize:9,color:T.muted,letterSpacing:1}}>AVG ADHERE</div>
                  </div>
                  <div style={{background:T.surface,borderRadius:12,padding:"12px 10px",textAlign:"center"}}>
                    <div style={{fontFamily:"Bebas Neue",fontSize:22,color:attn>0?T.danger:T.coachGreen}}>{attn}</div>
                    <div style={{fontFamily:"DM Sans",fontSize:9,color:T.muted,letterSpacing:1}}>NEED ATTN</div>
                  </div>
                </div>
                {/* Client mini-list */}
                <div style={{display:"flex",flexDirection:"column",gap:6}}>
                  {coachClients.map(c=>{
                    const sm=statusMeta[c.status];
                    return (
                      <div key={c.id} style={{display:"flex",alignItems:"center",gap:10,background:T.surface,borderRadius:10,padding:"8px 12px"}}>
                        <Avatar initials={c.avatar} color={c.avatarColor} size={28}/>
                        <div style={{flex:1}}>
                          <div style={{fontFamily:"DM Sans",fontSize:12,fontWeight:500,color:T.text}}>{c.name}</div>
                          <div style={{fontFamily:"JetBrains Mono",fontSize:9,color:T.muted}}>{c.sport} · {c.goal}</div>
                        </div>
                        <Badge label={sm.label} color={sm.color}/>
                        <div style={{fontFamily:"Bebas Neue",fontSize:14,color:c.adherence>=80?T.coachGreen:c.adherence>=65?T.warn:T.danger}}>{c.adherence}%</div>
                      </div>
                    );
                  })}
                </div>
              </div>
            );
          })}
        </div>
      )}

      {tab==="coaches"&&(
        <div style={{background:T.card,border:`1px solid ${T.border}`,borderRadius:18,overflow:"hidden"}}>
          <div style={{padding:"18px 24px",borderBottom:`1px solid ${T.border}`}}>
            <div style={{fontFamily:"Bebas Neue",fontSize:18,letterSpacing:2,color:T.text}}>COACHING STAFF PERFORMANCE</div>
          </div>
          {COACH_META.map((cm,i)=>{
            const cc=allClients.filter(c=>cm.clientIds.includes(c.id));
            const ca=cc.length?Math.round(cc.reduce((a,c)=>a+c.adherence,0)/cc.length):0;
            const topClient=cc.sort((a,b)=>b.adherence-a.adherence)[0];
            const worstClient=cc.sort((a,b)=>a.adherence-b.adherence)[0];
            return (
              <div key={cm.coachId} style={{padding:"20px 24px",borderBottom:i<COACH_META.length-1?`1px solid ${T.border}`:"none"}}>
                <div style={{display:"flex",alignItems:"center",gap:14,marginBottom:14}}>
                  <div style={{width:46,height:46,borderRadius:"50%",background:`${cm.avatarColor}25`,border:`2px solid ${cm.avatarColor}55`,display:"flex",alignItems:"center",justifyContent:"center",fontFamily:"Bebas Neue",fontSize:18,color:cm.avatarColor}}>
                    {cm.name.split(" ").map(n=>n[0]).join("")}
                  </div>
                  <div style={{flex:1}}>
                    <div style={{fontFamily:"DM Sans",fontSize:14,fontWeight:600,color:T.text}}>{cm.name}</div>
                    <div style={{fontFamily:"JetBrains Mono",fontSize:10,color:T.muted}}>{cm.email} · {cm.role}</div>
                  </div>
                  <Badge label={`${cc.length} Athletes`} color={cm.avatarColor}/>
                  <div style={{textAlign:"right"}}>
                    <div style={{fontFamily:"Bebas Neue",fontSize:24,color:ca>=80?T.coachGreen:ca>=65?T.warn:T.danger}}>{ca}%</div>
                    <div style={{fontFamily:"DM Sans",fontSize:9,color:T.muted,letterSpacing:1}}>TEAM ADHERENCE</div>
                  </div>
                </div>
                <div style={{display:"flex",gap:20}}>
                  <div style={{fontFamily:"DM Sans",fontSize:11,color:T.muted}}>🏆 Top: <span style={{color:T.coachGreen,fontWeight:600}}>{topClient?.name}</span> ({topClient?.adherence}%)</div>
                  <div style={{fontFamily:"DM Sans",fontSize:11,color:T.muted}}>⚠️ Needs focus: <span style={{color:T.warn,fontWeight:600}}>{worstClient?.name}</span> ({worstClient?.adherence}%)</div>
                  <div style={{fontFamily:"DM Sans",fontSize:11,color:T.muted}}>On Track: <span style={{color:T.coachGreen,fontWeight:600}}>{cc.filter(c=>c.status==="on-track").length}/{cc.length}</span></div>
                </div>
              </div>
            );
          })}
        </div>
      )}

      {tab==="clients"&&(
        <div style={{background:T.card,border:`1px solid ${T.border}`,borderRadius:18,overflow:"hidden"}}>
          <div style={{padding:"18px 24px",borderBottom:`1px solid ${T.border}`}}>
            <div style={{fontFamily:"Bebas Neue",fontSize:18,letterSpacing:2,color:T.text}}>ALL ATHLETES — ADMIN VIEW</div>
          </div>
          {allClients.map((c,i)=>{
            const coach=COACH_META.find(cm=>cm.clientIds.includes(c.id));
            const sm=statusMeta[c.status];
            return (
              <div key={c.id} style={{padding:"14px 24px",borderBottom:i<allClients.length-1?`1px solid ${T.border}`:"none",display:"flex",alignItems:"center",gap:12}}>
                <Avatar initials={c.avatar} color={c.avatarColor} size={36}/>
                <div style={{flex:1}}>
                  <div style={{display:"flex",alignItems:"center",gap:8}}>
                    <span style={{fontFamily:"DM Sans",fontSize:13,fontWeight:600,color:T.text}}>{c.name}</span>
                    <Badge label={sm.label} color={sm.color}/>
                  </div>
                  <div style={{fontFamily:"JetBrains Mono",fontSize:10,color:T.muted}}>{c.email} · {c.sport} · {c.goal}</div>
                </div>
                <div style={{textAlign:"center",minWidth:80}}>
                  <div style={{fontFamily:"DM Sans",fontSize:10,color:T.muted}}>Coach</div>
                  <div style={{fontFamily:"DM Sans",fontSize:11,fontWeight:600,color:coach?.avatarColor||T.muted}}>{coach?.name||"Unassigned"}</div>
                </div>
                <div style={{textAlign:"center",minWidth:52}}>
                  <div style={{fontFamily:"Bebas Neue",fontSize:20,color:c.adherence>=80?T.coachGreen:c.adherence>=65?T.warn:T.danger}}>{c.adherence}%</div>
                  <div style={{fontFamily:"DM Sans",fontSize:8,color:T.muted,letterSpacing:1}}>ADHERE</div>
                </div>
                <div style={{textAlign:"center",minWidth:44}}>
                  <div style={{fontFamily:"Bebas Neue",fontSize:20,color:c.nextCheckIn<=1?T.danger:T.muted}}>{c.nextCheckIn}d</div>
                  <div style={{fontFamily:"DM Sans",fontSize:8,color:T.muted,letterSpacing:1}}>CHECK</div>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

// ── Calendar Panel ────────────────────────────────────────────────────────────
const EVENT_TYPES=[
  {key:"check-in",   label:"Check-In",    color:"#3b82f6", icon:"📋"},
  {key:"training",   label:"Training",    color:"#f97316", icon:"💪"},
  {key:"meal-prep",  label:"Meal Prep",   color:"#22c55e", icon:"🥗"},
  {key:"education",  label:"Education",   color:"#a855f7", icon:"📚"},
  {key:"challenge",  label:"Challenge",   color:"#FF9A52", icon:"🏆"},
  {key:"other",      label:"Other",       color:"#94a3b8", icon:"📌"},
];
const MONTH_NAMES=["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
const DAY_NAMES=["Sun","Mon","Tue","Wed","Thu","Fri","Sat"];

function CalendarPanel({clients,calEvents,setCalEvents}){
  const today=new Date();
  const [year,setYear]=useState(today.getFullYear());
  const [month,setMonth]=useState(today.getMonth());
  const [selClient,setSelClient]=useState(clients[0]?.id||null);
  const [showAddModal,setShowAddModal]=useState(false);
  const [selectedDay,setSelectedDay]=useState(null);
  const [newEvent,setNewEvent]=useState({title:"",date:"",time:"",type:"check-in",link:"",notes:""});

  const firstDay=new Date(year,month,1).getDay();
  const daysInMonth=new Date(year,month+1,0).getDate();
  const prevMonth=()=>{if(month===0){setMonth(11);setYear(y=>y-1);}else setMonth(m=>m-1);};
  const nextMonth=()=>{if(month===11){setMonth(0);setYear(y=>y+1);}else setMonth(m=>m+1);};

  const clientEvents=(calEvents||[]).filter(e=>e.clientId===selClient&&new Date(e.date).getMonth()===month&&new Date(e.date).getFullYear()===year);
  const eventsForDay=(day)=>clientEvents.filter(e=>new Date(e.date).getDate()===day);

  const openAdd=(day)=>{
    const d=new Date(year,month,day);
    const ds=`${year}-${String(month+1).padStart(2,"0")}-${String(day).padStart(2,"0")}`;
    setNewEvent({title:"",date:ds,time:"09:00",type:"check-in",link:"",notes:""});
    setSelectedDay(day); setShowAddModal(true);
  };
  const saveEvent=()=>{
    if(!newEvent.title.trim()||!newEvent.date)return;
    const evt={id:Date.now(),clientId:selClient,...newEvent};
    setCalEvents(p=>[...(p||[]),evt]);
    setShowAddModal(false);
  };
  const deleteEvent=(id)=>setCalEvents(p=>(p||[]).filter(e=>e.id!==id));

  const selClientObj=clients.find(c=>c.id===selClient);

  return (
    <div style={{display:"flex",flexDirection:"column",gap:20}}>
      {/* Add event modal */}
      {showAddModal&&(
        <div style={{position:"fixed",inset:0,background:"#000000cc",zIndex:500,display:"flex",alignItems:"center",justifyContent:"center",padding:20}} onClick={e=>{if(e.target===e.currentTarget)setShowAddModal(false);}}>
          <div style={{background:T.card,border:`1px solid ${T.accent}44`,borderRadius:20,padding:28,width:"100%",maxWidth:500,animation:"fadeUp .2s ease",maxHeight:"90vh",overflowY:"auto"}}>
            <div style={{fontFamily:"Bebas Neue",fontSize:22,letterSpacing:2,color:T.text,marginBottom:4}}>ADD CALENDAR EVENT</div>
            <div style={{fontFamily:"DM Sans",fontSize:11,color:T.muted,marginBottom:20}}>For {selClientObj?.name} · {newEvent.date}</div>
            <FormField label="Event Title" required>
              <input value={newEvent.title} onChange={e=>setNewEvent(p=>({...p,title:e.target.value}))} placeholder="e.g. Weekly check-in, Carb load day…"
                style={{width:"100%",background:T.surface,border:`1px solid ${T.border}`,borderRadius:10,padding:"10px 14px",color:T.text,fontFamily:"DM Sans",fontSize:13,outline:"none"}}/>
            </FormField>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginBottom:14}}>
              <FormField label="Date">
                <input type="date" value={newEvent.date} onChange={e=>setNewEvent(p=>({...p,date:e.target.value}))}
                  style={{width:"100%",background:T.surface,border:`1px solid ${T.border}`,borderRadius:10,padding:"10px 14px",color:T.text,fontFamily:"DM Sans",fontSize:13,outline:"none"}}/>
              </FormField>
              <FormField label="Time">
                <input type="time" value={newEvent.time} onChange={e=>setNewEvent(p=>({...p,time:e.target.value}))}
                  style={{width:"100%",background:T.surface,border:`1px solid ${T.border}`,borderRadius:10,padding:"10px 14px",color:T.text,fontFamily:"DM Sans",fontSize:13,outline:"none"}}/>
              </FormField>
            </div>
            <FormField label="Event Type">
              <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
                {EVENT_TYPES.map(et=>(
                  <button key={et.key} onClick={()=>setNewEvent(p=>({...p,type:et.key}))}
                    style={{background:newEvent.type===et.key?`${et.color}30`:`${et.color}0d`,border:`1px solid ${newEvent.type===et.key?et.color:et.color+"40"}`,borderRadius:8,padding:"6px 12px",color:newEvent.type===et.key?et.color:`${et.color}99`,fontFamily:"DM Sans",fontSize:12,cursor:"pointer",transition:"all .15s"}}>
                    {et.icon} {et.label}
                  </button>
                ))}
              </div>
            </FormField>
            <FormField label="Link (optional)" sub="Zoom, Google Meet, resource URL…">
              <input value={newEvent.link} onChange={e=>setNewEvent(p=>({...p,link:e.target.value}))} placeholder="https://…"
                style={{width:"100%",background:T.surface,border:`1px solid ${T.border}`,borderRadius:10,padding:"10px 14px",color:T.text,fontFamily:"DM Sans",fontSize:13,outline:"none"}}/>
            </FormField>
            <FormField label="Notes (optional)">
              <textarea value={newEvent.notes} onChange={e=>setNewEvent(p=>({...p,notes:e.target.value}))} placeholder="Instructions, reminders, or context for the athlete…"
                style={{width:"100%",background:T.surface,border:`1px solid ${T.border}`,borderRadius:10,padding:"10px 14px",color:T.text,fontFamily:"DM Sans",fontSize:13,outline:"none",resize:"vertical",minHeight:72}}/>
            </FormField>
            <div style={{display:"flex",gap:10,marginTop:6}}>
              <button onClick={()=>setShowAddModal(false)} style={{flex:1,background:"none",border:`1px solid ${T.border}`,borderRadius:10,padding:11,color:T.muted,fontFamily:"DM Sans",fontSize:13,cursor:"pointer"}}>Cancel</button>
              <button onClick={saveEvent} disabled={!newEvent.title.trim()}
                style={{flex:2,background:newEvent.title.trim()?T.accent:T.border,color:newEvent.title.trim()?T.bg:T.muted,border:"none",borderRadius:10,padding:11,fontFamily:"Bebas Neue",fontSize:16,letterSpacing:1.5,cursor:newEvent.title.trim()?"pointer":"default",transition:"all .2s"}}>
                SAVE EVENT
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Header */}
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
        <div>
          <div style={{fontFamily:"Bebas Neue",fontSize:28,letterSpacing:2,color:T.text}}>ATHLETE CALENDAR</div>
          <div style={{fontFamily:"DM Sans",fontSize:12,color:T.muted,marginTop:4}}>Schedule check-ins, training sessions, resources and links</div>
        </div>
        <button onClick={()=>{setNewEvent({title:"",date:`${year}-${String(month+1).padStart(2,"0")}-01`,time:"09:00",type:"check-in",link:"",notes:""});setShowAddModal(true);}}
          style={{background:T.accent,color:T.bg,border:"none",borderRadius:10,padding:"10px 22px",fontFamily:"Bebas Neue",fontSize:16,letterSpacing:1.5,cursor:"pointer"}}
          onMouseEnter={e=>e.currentTarget.style.opacity=.85} onMouseLeave={e=>e.currentTarget.style.opacity=1}>+ ADD EVENT</button>
      </div>

      {/* Client selector */}
      <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
        {clients.map(c=>(
          <button key={c.id} onClick={()=>setSelClient(c.id)}
            style={{display:"flex",alignItems:"center",gap:8,background:selClient===c.id?`${c.avatarColor}20`:T.card,border:`1px solid ${selClient===c.id?c.avatarColor+"66":T.border}`,borderRadius:10,padding:"8px 14px",cursor:"pointer",transition:"all .2s"}}>
            <Avatar initials={c.avatar} color={c.avatarColor} size={26}/>
            <span style={{fontFamily:"DM Sans",fontSize:12,fontWeight:selClient===c.id?600:400,color:selClient===c.id?T.text:T.muted}}>{c.name.split(" ")[0]}</span>
            {calEvents?.filter(e=>e.clientId===c.id).length>0&&<span style={{fontFamily:"JetBrains Mono",fontSize:9,color:c.avatarColor}}>{calEvents.filter(e=>e.clientId===c.id).length}</span>}
          </button>
        ))}
      </div>

      <div style={{display:"grid",gridTemplateColumns:"1fr 340px",gap:16}}>
        {/* Calendar grid */}
        <div style={{background:T.card,border:`1px solid ${T.border}`,borderRadius:18,overflow:"hidden"}}>
          {/* Month nav */}
          <div style={{padding:"16px 22px",borderBottom:`1px solid ${T.border}`,display:"flex",alignItems:"center",justifyContent:"space-between"}}>
            <button onClick={prevMonth} style={{background:"none",border:"none",color:T.muted,cursor:"pointer",fontSize:18,padding:"4px 10px"}}>‹</button>
            <div style={{fontFamily:"Bebas Neue",fontSize:20,letterSpacing:2,color:T.text}}>{MONTH_NAMES[month]} {year}</div>
            <button onClick={nextMonth} style={{background:"none",border:"none",color:T.muted,cursor:"pointer",fontSize:18,padding:"4px 10px"}}>›</button>
          </div>
          {/* Day headers */}
          <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",borderBottom:`1px solid ${T.border}`}}>
            {DAY_NAMES.map(d=>(
              <div key={d} style={{padding:"8px 4px",textAlign:"center",fontFamily:"Bebas Neue",fontSize:11,letterSpacing:1,color:T.muted}}>{d}</div>
            ))}
          </div>
          {/* Days grid */}
          <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:0}}>
            {Array.from({length:firstDay}).map((_,i)=><div key={`e${i}`} style={{minHeight:88,borderRight:`1px solid ${T.border}22`,borderBottom:`1px solid ${T.border}22`}}/>)}
            {Array.from({length:daysInMonth}).map((_,i)=>{
              const day=i+1;
              const isToday=year===today.getFullYear()&&month===today.getMonth()&&day===today.getDate();
              const dayEvts=eventsForDay(day);
              return (
                <div key={day} onClick={()=>openAdd(day)}
                  style={{minHeight:88,borderRight:`1px solid ${T.border}22`,borderBottom:`1px solid ${T.border}22`,padding:"6px 6px",cursor:"pointer",transition:"background .15s",background:isToday?`${T.accent}08`:"transparent"}}
                  onMouseEnter={e=>e.currentTarget.style.background=isToday?`${T.accent}14`:`${T.surface}99`}
                  onMouseLeave={e=>e.currentTarget.style.background=isToday?`${T.accent}08`:"transparent"}>
                  <div style={{fontFamily:"Bebas Neue",fontSize:13,color:isToday?T.accent:T.muted,marginBottom:4,display:"flex",alignItems:"center",gap:4}}>
                    {day}{isToday&&<div style={{width:5,height:5,borderRadius:"50%",background:T.accent}}/>}
                  </div>
                  {dayEvts.map(evt=>{
                    const et=EVENT_TYPES.find(t=>t.key===evt.type)||EVENT_TYPES[5];
                    return (
                      <div key={evt.id} onClick={e=>{e.stopPropagation();}} title={`${evt.title}${evt.link?" — "+evt.link:""}`}
                        style={{background:`${et.color}18`,border:`1px solid ${et.color}44`,borderRadius:5,padding:"2px 5px",marginBottom:2,fontSize:9,fontFamily:"DM Sans",color:et.color,fontWeight:500,overflow:"hidden",whiteSpace:"nowrap",textOverflow:"ellipsis",maxWidth:"100%"}}>
                        {et.icon} {evt.title}
                      </div>
                    );
                  })}
                  {dayEvts.length===0&&<div style={{width:"100%",height:2,background:T.border+"44",borderRadius:99,marginTop:4}}/>}
                </div>
              );
            })}
          </div>
        </div>

        {/* Events sidebar */}
        <div style={{display:"flex",flexDirection:"column",gap:10}}>
          <div style={{background:T.card,border:`1px solid ${T.border}`,borderRadius:14,padding:"14px 16px"}}>
            <div style={{fontFamily:"Bebas Neue",fontSize:14,letterSpacing:2,color:T.text,marginBottom:12}}>THIS MONTH'S EVENTS</div>
            {clientEvents.length===0&&<div style={{fontFamily:"DM Sans",fontSize:12,color:T.muted,textAlign:"center",padding:"20px 0"}}>No events this month.<br/>Click any day to add one.</div>}
            {clientEvents.sort((a,b)=>new Date(a.date)-new Date(b.date)).map(evt=>{
              const et=EVENT_TYPES.find(t=>t.key===evt.type)||EVENT_TYPES[5];
              const d=new Date(evt.date);
              return (
                <div key={evt.id} style={{background:T.surface,border:`1px solid ${T.border}`,borderRadius:12,padding:"12px 14px",marginBottom:8}}>
                  <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",marginBottom:4}}>
                    <div style={{display:"flex",alignItems:"center",gap:7}}>
                      <span style={{fontSize:14}}>{et.icon}</span>
                      <div>
                        <div style={{fontFamily:"DM Sans",fontSize:12,fontWeight:600,color:T.text}}>{evt.title}</div>
                        <div style={{fontFamily:"JetBrains Mono",fontSize:9,color:T.muted}}>{MONTH_NAMES[d.getMonth()]} {d.getDate()} {evt.time&&`· ${evt.time}`}</div>
                      </div>
                    </div>
                    <button onClick={()=>deleteEvent(evt.id)} style={{background:"none",border:"none",color:T.muted,cursor:"pointer",fontSize:12,padding:2}}
                      onMouseEnter={e=>e.currentTarget.style.color=T.danger} onMouseLeave={e=>e.currentTarget.style.color=T.muted}>✕</button>
                  </div>
                  <Badge label={et.label} color={et.color}/>
                  {evt.link&&(
                    <div style={{marginTop:7,display:"flex",alignItems:"center",gap:5}}>
                      <span style={{fontSize:10}}>🔗</span>
                      <a href={evt.link} target="_blank" rel="noopener noreferrer"
                        style={{fontFamily:"DM Sans",fontSize:11,color:T.accent,textDecoration:"none",wordBreak:"break-all"}}
                        onMouseEnter={e=>e.currentTarget.style.textDecoration="underline"} onMouseLeave={e=>e.currentTarget.style.textDecoration="none"}>
                        {evt.link.replace(/^https?:\/\/(www\.)?/,"")}
                      </a>
                    </div>
                  )}
                  {evt.notes&&<div style={{fontFamily:"DM Sans",fontSize:11,color:T.muted,marginTop:6,lineHeight:1.5}}>{evt.notes}</div>}
                </div>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
}

// ── Form helpers ──────────────────────────────────────────────────────────────
const FormField=({label,children,required,sub})=>(
  <div style={{marginBottom:14}}>
    <label style={{fontFamily:"DM Sans",fontSize:11,color:T.muted,letterSpacing:1,textTransform:"uppercase",display:"block",marginBottom:5}}>
      {label}{required&&<span style={{color:T.danger}}> *</span>}
      {sub&&<span style={{fontWeight:400,textTransform:"none",letterSpacing:0,color:T.muted,fontSize:10,marginLeft:6}}>{sub}</span>}
    </label>
    {children}
  </div>
);
const inputStyle={width:"100%",background:T.surface,border:`1px solid ${T.border}`,borderRadius:10,padding:"10px 14px",color:T.text,fontFamily:"DM Sans",fontSize:13,outline:"none"};
const selectStyle={...inputStyle,cursor:"pointer"};

// ── Add Client Modal ──────────────────────────────────────────────────────────
function AddClientModal({onClose,onAdd}){
  const SPORTS=["Triathlon","Powerlifting","CrossFit","Swimming","Running","Cycling","HIIT","Gymnastics","Football","Other"];
  const GOALS=["Performance","Strength","Fat Loss","Endurance","Muscle Gain","Maintenance","Health","Recomposition"];
  const [step,setStep]=useState(1);
  const [saving,setSaving]=useState(false);
  const [form,setForm]=useState({
    // Personal
    name:"",email:"",phone:"",dob:"",sport:"Running",goal:"Performance",
    // Login
    loginEmail:"",password:"",
    // Body stats
    weight:"",height:"",bodyFat:"",
    // Macros
    calories:"",protein:"",carbs:"",fat:"",
    // Notes
    coachNotes:"",healthNotes:"",personalisation:"",
    // Tags
    tags:"",
  });
  const set=k=>e=>setForm(p=>({...p,[k]:e.target.value}));
  const avatarColor=["#3b82f6","#a855f7","#f97316","#22c55e","#FF9A52","#ef4444","#06b6d4"][Math.floor(Math.random()*7)];

  const valid1=form.name.trim()&&form.email.trim()&&form.sport&&form.goal;
  const valid2=form.loginEmail.trim()&&form.password.trim()&&form.password.length>=6;
  const valid3=form.calories&&form.protein&&form.carbs&&form.fat;

  const save=()=>{
    setSaving(true);
    setTimeout(()=>{
      const initials=form.name.trim().split(" ").map(n=>n[0]).join("").slice(0,2).toUpperCase();
      const newClient={
        id:Date.now(),
        name:form.name.trim(),
        email:form.loginEmail.trim()||form.email.trim(),
        sport:form.sport,
        goal:form.goal,
        avatar:initials,
        avatarColor,
        macroGoals:{calories:+form.calories,protein:+form.protein,carbs:+form.carbs,fat:+form.fat},
        todayActual:{calories:0,protein:0,carbs:0,fat:0},
        adherence:0,streak:0,status:"under",nextCheckIn:7,
        weight:form.weight||"—",
        tags:form.tags.split(",").map(t=>t.trim()).filter(Boolean),
        joinDate:new Date().toISOString().slice(0,10),
        checkIns:[],
        weightHistory:[],moodLog:{},trainingLog:[],foodDiary:{},weekHistory:[],
        coachNotes:form.coachNotes,
        healthNotes:form.healthNotes,
        personalisation:form.personalisation,
        phone:form.phone,dob:form.dob,height:form.height,bodyFat:form.bodyFat,
        loginEmail:form.loginEmail,
        password:form.password,
      };
      onAdd(newClient);
      setSaving(false);
    },1000);
  };

  const STEPS=[{n:1,label:"Profile"},{n:2,label:"Login"},{n:3,label:"Targets"},{n:4,label:"Notes"}];

  return (
    <div style={{position:"fixed",inset:0,background:"#000000d0",zIndex:600,display:"flex",alignItems:"center",justifyContent:"center",padding:20}} onClick={e=>{if(e.target===e.currentTarget)onClose();}}>
      <div style={{background:T.card,border:`1px solid ${T.accent}44`,borderRadius:22,width:"100%",maxWidth:560,maxHeight:"92vh",overflow:"hidden",animation:"fadeUp .25s ease",display:"flex",flexDirection:"column"}}>
        {/* Modal header */}
        <div style={{padding:"22px 28px",borderBottom:`1px solid ${T.border}`,display:"flex",alignItems:"center",justifyContent:"space-between",flexShrink:0}}>
          <div>
            <div style={{fontFamily:"Bebas Neue",fontSize:22,letterSpacing:2,color:T.text}}>ADD NEW ATHLETE</div>
            <div style={{fontFamily:"DM Sans",fontSize:11,color:T.muted,marginTop:3}}>Create a full client profile with login credentials</div>
          </div>
          <button onClick={onClose} style={{background:"none",border:"none",color:T.muted,cursor:"pointer",fontSize:20,padding:4}}
            onMouseEnter={e=>e.currentTarget.style.color=T.danger} onMouseLeave={e=>e.currentTarget.style.color=T.muted}>✕</button>
        </div>
        {/* Step indicators */}
        <div style={{display:"flex",padding:"14px 28px",gap:6,borderBottom:`1px solid ${T.border}`,flexShrink:0}}>
          {STEPS.map(s=>(
            <div key={s.n} onClick={()=>{if(s.n<step||(s.n===2&&valid1)||(s.n===3&&valid2)||(s.n===4&&valid3))setStep(s.n);}}
              style={{flex:1,padding:"7px 4px",borderRadius:8,textAlign:"center",cursor:"pointer",background:step===s.n?T.accent:step>s.n?`${T.coachGreen}18`:`${T.border}40`,border:`1px solid ${step===s.n?T.accent:step>s.n?T.coachGreen+"40":T.border+"44"}`,transition:"all .2s"}}>
              <div style={{fontFamily:"Bebas Neue",fontSize:12,letterSpacing:1,color:step===s.n?T.bg:step>s.n?T.coachGreen:T.muted}}>{step>s.n?"✓ ":""}{s.label}</div>
            </div>
          ))}
        </div>
        {/* Form body */}
        <div style={{padding:"22px 28px",overflowY:"auto",flex:1}}>
          {step===1&&(
            <>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
                <FormField label="Full Name" required>
                  <input value={form.name} onChange={set("name")} placeholder="e.g. Alex Morgan" style={inputStyle}/>
                </FormField>
                <FormField label="Contact Email" required>
                  <input value={form.email} onChange={set("email")} placeholder="client@email.com" style={inputStyle}/>
                </FormField>
              </div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
                <FormField label="Phone">
                  <input value={form.phone} onChange={set("phone")} placeholder="+44 7700 000000" style={inputStyle}/>
                </FormField>
                <FormField label="Date of Birth">
                  <input type="date" value={form.dob} onChange={set("dob")} style={inputStyle}/>
                </FormField>
              </div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
                <FormField label="Sport" required>
                  <select value={form.sport} onChange={set("sport")} style={selectStyle}>
                    {SPORTS.map(s=><option key={s} value={s}>{s}</option>)}
                  </select>
                </FormField>
                <FormField label="Primary Goal" required>
                  <select value={form.goal} onChange={set("goal")} style={selectStyle}>
                    {GOALS.map(g=><option key={g} value={g}>{g}</option>)}
                  </select>
                </FormField>
              </div>
              <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:12}}>
                <FormField label="Current Weight" sub="kg">
                  <input value={form.weight} onChange={set("weight")} placeholder="70.0" style={inputStyle}/>
                </FormField>
                <FormField label="Height" sub="cm">
                  <input value={form.height} onChange={set("height")} placeholder="175" style={inputStyle}/>
                </FormField>
                <FormField label="Body Fat %" sub="if known">
                  <input value={form.bodyFat} onChange={set("bodyFat")} placeholder="18" style={inputStyle}/>
                </FormField>
              </div>
              <FormField label="Tags" sub="comma-separated">
                <input value={form.tags} onChange={set("tags")} placeholder="Elite, Performance, Fat Loss…" style={inputStyle}/>
              </FormField>
            </>
          )}
          {step===2&&(
            <>
              <div style={{background:`${T.info||T.accent}0d`,border:`1px solid ${T.info||T.accent}30`,borderRadius:12,padding:"12px 16px",marginBottom:18}}>
                <div style={{fontFamily:"DM Sans",fontSize:12,color:T.muted}}>🔑 These credentials give <strong style={{color:T.text}}>{form.name||"the athlete"}</strong> access to their client portal. Share them securely after creating the profile.</div>
              </div>
              <FormField label="Portal Login Email" required>
                <input value={form.loginEmail} onChange={set("loginEmail")} placeholder={form.email||"athlete@email.com"} style={inputStyle}/>
              </FormField>
              <FormField label="Password" required sub="min 6 characters">
                <input type="text" value={form.password} onChange={set("password")} placeholder="Create a secure password…" style={inputStyle}/>
              </FormField>
              {form.password&&form.password.length<6&&(
                <div style={{fontFamily:"DM Sans",fontSize:11,color:T.danger,marginTop:-10,marginBottom:10}}>Password must be at least 6 characters</div>
              )}
              {form.loginEmail&&form.password&&form.password.length>=6&&(
                <div style={{background:`${T.coachGreen}0d`,border:`1px solid ${T.coachGreen}30`,borderRadius:12,padding:"12px 16px",marginTop:4}}>
                  <div style={{fontFamily:"Bebas Neue",fontSize:12,letterSpacing:1,color:T.coachGreen,marginBottom:4}}>CREDENTIALS PREVIEW</div>
                  <div style={{fontFamily:"JetBrains Mono",fontSize:11,color:T.muted}}>Email: <span style={{color:T.text}}>{form.loginEmail}</span></div>
                  <div style={{fontFamily:"JetBrains Mono",fontSize:11,color:T.muted}}>Pass: <span style={{color:T.text}}>{form.password}</span></div>
                </div>
              )}
            </>
          )}
          {step===3&&(
            <>
              <div style={{background:`${T.warn}0d`,border:`1px solid ${T.warn}30`,borderRadius:12,padding:"12px 16px",marginBottom:18}}>
                <div style={{fontFamily:"DM Sans",fontSize:12,color:T.muted}}>📊 Set daily macro targets for <strong style={{color:T.text}}>{form.name||"this athlete"}</strong>. These will pre-populate their tracking — reducing their daily workload.</div>
              </div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
                <FormField label="Daily Calories" required sub="kcal">
                  <input type="number" value={form.calories} onChange={set("calories")} placeholder="2500" style={inputStyle}/>
                </FormField>
                <FormField label="Protein" required sub="g/day">
                  <input type="number" value={form.protein} onChange={set("protein")} placeholder="185" style={inputStyle}/>
                </FormField>
                <FormField label="Carbohydrates" required sub="g/day">
                  <input type="number" value={form.carbs} onChange={set("carbs")} placeholder="280" style={inputStyle}/>
                </FormField>
                <FormField label="Fat" required sub="g/day">
                  <input type="number" value={form.fat} onChange={set("fat")} placeholder="75" style={inputStyle}/>
                </FormField>
              </div>
              {form.calories&&form.protein&&form.carbs&&form.fat&&(
                <div style={{background:T.surface,borderRadius:12,padding:"14px 16px",marginTop:4}}>
                  <div style={{fontFamily:"Bebas Neue",fontSize:12,letterSpacing:1,color:T.muted,marginBottom:10}}>MACRO SPLIT PREVIEW</div>
                  <div style={{display:"flex",gap:12}}>
                    {[{label:"PROTEIN",val:+form.protein*4,color:T.protein},{label:"CARBS",val:+form.carbs*4,color:T.carbs},{label:"FAT",val:+form.fat*9,color:T.fat}].map(m=>{
                      const pct=Math.round((m.val/+form.calories)*100);
                      return (
                        <div key={m.label} style={{flex:1,textAlign:"center"}}>
                          <div style={{fontFamily:"Bebas Neue",fontSize:20,color:m.color}}>{pct}%</div>
                          <div style={{fontFamily:"DM Sans",fontSize:9,color:T.muted,letterSpacing:1}}>{m.label}</div>
                          <div style={{height:3,background:T.border,borderRadius:99,marginTop:4}}><div style={{height:"100%",width:`${pct}%`,background:m.color,borderRadius:99}}/></div>
                        </div>
                      );
                    })}
                  </div>
                </div>
              )}
            </>
          )}
          {step===4&&(
            <>
              <FormField label="Coach Notes" sub="private — not visible to athlete">
                <textarea value={form.coachNotes} onChange={set("coachNotes")} placeholder="Key observations, coaching style notes, what motivates them…"
                  style={{...inputStyle,resize:"vertical",minHeight:80}}/>
              </FormField>
              <FormField label="Health & Medical Notes" sub="injuries, intolerances, medications">
                <textarea value={form.healthNotes} onChange={set("healthNotes")} placeholder="e.g. Previous hamstring injury, lactose intolerant, thyroid medication…"
                  style={{...inputStyle,resize:"vertical",minHeight:72}}/>
              </FormField>
              <FormField label="Personalisation Notes" sub="lifestyle, preferences, schedule">
                <textarea value={form.personalisation} onChange={set("personalisation")} placeholder="e.g. Works night shifts, loves meal prepping on Sundays, prefers higher carb on training days…"
                  style={{...inputStyle,resize:"vertical",minHeight:72}}/>
              </FormField>
              {/* Summary */}
              <div style={{background:T.surface,borderRadius:14,padding:"16px 18px",marginTop:4}}>
                <div style={{fontFamily:"Bebas Neue",fontSize:13,letterSpacing:1.5,color:T.muted,marginBottom:10}}>PROFILE SUMMARY</div>
                <div style={{display:"flex",gap:12,alignItems:"center",marginBottom:12}}>
                  <div style={{width:44,height:44,borderRadius:"50%",background:`${avatarColor}25`,border:`2px solid ${avatarColor}55`,display:"flex",alignItems:"center",justifyContent:"center",fontFamily:"Bebas Neue",fontSize:16,color:avatarColor}}>
                    {form.name.trim().split(" ").map(n=>n[0]).join("").slice(0,2)||"?"}
                  </div>
                  <div>
                    <div style={{fontFamily:"DM Sans",fontSize:14,fontWeight:600,color:T.text}}>{form.name||"—"}</div>
                    <div style={{fontFamily:"JetBrains Mono",fontSize:10,color:T.muted}}>{form.loginEmail} · {form.sport} · {form.goal}</div>
                  </div>
                </div>
                <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:6,fontFamily:"DM Sans",fontSize:11}}>
                  <div style={{color:T.muted}}>Calories: <span style={{color:T.accent,fontWeight:600}}>{form.calories||"—"} kcal</span></div>
                  <div style={{color:T.muted}}>Protein: <span style={{color:T.protein,fontWeight:600}}>{form.protein||"—"}g</span></div>
                  <div style={{color:T.muted}}>Carbs: <span style={{color:T.carbs,fontWeight:600}}>{form.carbs||"—"}g</span></div>
                  <div style={{color:T.muted}}>Fat: <span style={{color:T.fat,fontWeight:600}}>{form.fat||"—"}g</span></div>
                </div>
              </div>
            </>
          )}
        </div>
        {/* Footer */}
        <div style={{padding:"16px 28px",borderTop:`1px solid ${T.border}`,display:"flex",gap:10,flexShrink:0}}>
          {step>1&&<button onClick={()=>setStep(s=>s-1)} style={{flex:1,background:"none",border:`1px solid ${T.border}`,borderRadius:10,padding:11,color:T.muted,fontFamily:"DM Sans",fontSize:13,cursor:"pointer"}}>← Back</button>}
          {step<4&&(
            <button onClick={()=>setStep(s=>s+1)}
              disabled={step===1?!valid1:step===2?!valid2:false}
              style={{flex:2,background:(step===1?valid1:step===2?valid2:true)?T.accent:T.border,color:(step===1?valid1:step===2?valid2:true)?T.bg:T.muted,border:"none",borderRadius:10,padding:11,fontFamily:"Bebas Neue",fontSize:16,letterSpacing:1.5,cursor:(step===1?valid1:step===2?valid2:true)?"pointer":"default",transition:"all .2s"}}>
              NEXT STEP →
            </button>
          )}
          {step===4&&(
            <button onClick={save} disabled={saving||!valid3}
              style={{flex:2,background:valid3&&!saving?T.accent:T.border,color:valid3&&!saving?T.bg:T.muted,border:"none",borderRadius:10,padding:11,fontFamily:"Bebas Neue",fontSize:16,letterSpacing:1.5,cursor:valid3&&!saving?"pointer":"default",transition:"all .2s"}}>
              {saving?"CREATING ATHLETE…":"✓ CREATE ATHLETE"}
            </button>
          )}
        </div>
      </div>
    </div>
  );
}

// ── Seed messages ─────────────────────────────────────────────────────────────
const seedMessages=c=>({[c.id]:[
  {role:"assistant",isCoach:true,content:`Hey ${c.name.split(" ")[0]}! Ready to crush this week? Macros looking solid — let me know if you need any adjustments! 💪`,time:"09:14"},
  {role:"user",isCoach:false,content:"Thanks coach! Struggling to hit carb targets on training days.",time:"10:32"},
  {role:"assistant",isCoach:true,content:"Good catch. Try 60g oats pre-workout — bumps carbs without touching fat. Let me know how today's session goes!",time:"10:45"},
]});
const initAllMessages=()=>{const m={};CLIENTS.forEach(c=>Object.assign(m,seedMessages(c)));return m;};

// ── Main App ──────────────────────────────────────────────────────────────────
export default function CoachCMS(){
  const [coach,setCoach]               = useState(null);
  const [nav,setNav]                   = useState("overview");
  const [view,setView]                 = useState("list");
  const [selectedClient,setSelectedClient]=useState(null);
  const [clients,setClients]           = useState(CLIENTS);
  const [allMessages,setAllMessages]   = useState(initAllMessages);
  const [calEvents,setCalEvents]       = useState([]);
  const [showAddClient,setShowAddClient]=useState(false);

  const updateClient=(id,updates)=>setClients(p=>p.map(c=>c.id===id?{...c,...updates}:c));
  const goToMessages=()=>setNav("messages");

  const addClient=(newClient)=>{
    setClients(p=>[...p,newClient]);
    setAllMessages(p=>({...p,[newClient.id]:[]}));
    setShowAddClient(false);
  };

  if(!coach) return <CoachLogin onLogin={c=>{setCoach(c);setNav(c.isAdmin?"admin":"overview");}}/>;

  const visibleClients = coach.isAdmin ? clients : clients.filter(c=>{
    const cm=COACH_META.find(m=>m.coachId===coach.coachId);
    return cm?cm.clientIds.includes(c.id):true;
  });

  const alertCount=visibleClients.filter(c=>c.adherence<70||c.nextCheckIn<=1).length;
  const coachNavItems = [
    {id:"overview",label:"OVERVIEW"},
    {id:"calendar",label:"📅 CALENDAR"},
    {id:"messages",label:"💬 MESSAGES",highlight:true},
    {id:"content",label:"📁 CONTENT"},
  ];
  const adminNavItems = [{id:"admin",label:"⭐ ADMIN OVERVIEW"},...coachNavItems];
  const navItems = coach.isAdmin ? adminNavItems : coachNavItems;

  return (
    <div style={{minHeight:"100vh",background:T.bg,color:T.text,fontFamily:"DM Sans"}}>
      <style>{`
        *{box-sizing:border-box;margin:0;padding:0}
        ::-webkit-scrollbar{width:4px}::-webkit-scrollbar-track{background:${T.surface}}::-webkit-scrollbar-thumb{background:${T.border};border-radius:2px}
        input::placeholder,textarea::placeholder{color:${T.muted}} input,select,textarea{caret-color:${T.accent}}
        @keyframes pulse{0%,100%{transform:scale(.6);opacity:.4}50%{transform:scale(1);opacity:1}}
        @keyframes fadeUp{from{opacity:0;transform:translateY(12px)}to{opacity:1;transform:translateY(0)}}
        button{outline:none}
      `}</style>

      {/* Add Client Modal */}
      {showAddClient&&<AddClientModal onClose={()=>setShowAddClient(false)} onAdd={addClient}/>}

      {/* Header */}
      <div style={{borderBottom:`1px solid ${T.border}`,padding:"0 28px",display:"flex",alignItems:"center",justifyContent:"space-between",height:64,position:"sticky",top:0,background:T.bg+"f0",backdropFilter:"blur(12px)",zIndex:50}}>
        <div style={{display:"flex",alignItems:"center",gap:12}}>
          <img src={LOGO_SRC} alt="No Rule Nutrition" style={{width:40,height:40,borderRadius:"50%",objectFit:"cover",border:`2px solid ${T.accent}44`}}/>
          <div>
            <div style={{fontFamily:"Bebas Neue",fontSize:22,letterSpacing:2,lineHeight:1}}>
              <span style={{color:T.accent}}>NO RULES</span><span style={{color:T.text}}> NUTRITION</span>
            </div>
            <div style={{fontFamily:"DM Sans",fontSize:10,color:T.coachGreen,letterSpacing:2,textTransform:"uppercase",fontWeight:600}}>COACH CMS</div>
          </div>
        </div>
        <div style={{display:"flex",alignItems:"center",gap:12}}>
          {alertCount>0&&<div style={{display:"flex",alignItems:"center",gap:6,background:`${T.danger}18`,border:`1px solid ${T.danger}44`,borderRadius:99,padding:"4px 12px"}}><div style={{width:6,height:6,borderRadius:"50%",background:T.danger}}/><span style={{fontFamily:"DM Sans",fontSize:11,color:T.danger}}>{alertCount} client{alertCount>1?"s":""} need attention</span></div>}
          {coach.isAdmin&&<div style={{display:"flex",alignItems:"center",gap:6,background:`${T.accent}18`,border:`1px solid ${T.accent}44`,borderRadius:99,padding:"4px 12px"}}><span style={{fontFamily:"Bebas Neue",fontSize:11,color:T.accent,letterSpacing:1}}>⭐ HEAD COACH</span></div>}
          <div style={{display:"flex",alignItems:"center",gap:8,background:T.card,border:`1px solid ${T.border}`,borderRadius:10,padding:"6px 14px"}}>
            <div style={{width:32,height:32,borderRadius:"50%",background:`${T.coachGreen}30`,border:`2px solid ${T.coachGreen}60`,display:"flex",alignItems:"center",justifyContent:"center",fontFamily:"Bebas Neue",fontSize:14,color:T.coachGreen}}>{coach.name.split(" ").map(n=>n[0]).join("")}</div>
            <div><div style={{fontFamily:"DM Sans",fontSize:12,fontWeight:600,color:T.text}}>{coach.name}</div><div style={{fontFamily:"JetBrains Mono",fontSize:9,color:T.coachGreen}}>{coach.role}</div></div>
            <button onClick={()=>{setCoach(null);setNav("overview");}} style={{background:"none",border:"none",color:T.muted,cursor:"pointer",fontSize:12,fontFamily:"DM Sans",marginLeft:6}}
              onMouseEnter={e=>e.currentTarget.style.color=T.danger} onMouseLeave={e=>e.currentTarget.style.color=T.muted}>Sign out</button>
          </div>
        </div>
      </div>

      {/* Nav */}
      <div style={{borderBottom:`1px solid ${T.border}`,padding:"0 28px",display:"flex",alignItems:"center",gap:2}}>
        {navItems.map(n=>(
          <button key={n.id} onClick={()=>{setNav(n.id);if(n.id!=="overview"&&n.id!=="admin")setView("list");}}
            style={{padding:"14px 18px",background:"none",border:"none",cursor:"pointer",fontFamily:"Bebas Neue",fontSize:14,letterSpacing:1.5,
              color:nav===n.id?(n.highlight?T.coachGreen:T.accent):T.muted,
              borderBottom:nav===n.id?`2px solid ${n.highlight?T.coachGreen:T.accent}`:"2px solid transparent",
              transition:"all .2s",marginBottom:-1}}>
            {n.label}
          </button>
        ))}
        <div style={{marginLeft:"auto",fontFamily:"JetBrains Mono",fontSize:11,color:T.muted,paddingLeft:16}}>
          <span style={{color:T.accent}}>{visibleClients.length}</span> athletes · <span style={{color:T.coachGreen}}>{visibleClients.length?Math.round(visibleClients.reduce((a,c)=>a+c.adherence,0)/visibleClients.length):0}%</span> avg adherence
        </div>
      </div>

      {/* Page content */}
      <div style={{padding:28,maxWidth:1300,margin:"0 auto",animation:"fadeUp .3s ease"}}>

        {/* Admin dashboard */}
        {nav==="admin"&&<AdminDashboard allClients={clients}/>}

        {/* Overview / client roster with Add Client */}
        {nav==="overview"&&view==="list"&&(
          <div>
            <OverviewPanel clients={visibleClients} onSelectClient={setSelectedClient} setView={setView}
              onAddClient={()=>setShowAddClient(true)}/>
          </div>
        )}
        {nav==="overview"&&view==="client"&&selectedClient&&(
          <ClientDetailPanel client={visibleClients.find(c=>c.id===selectedClient.id)} onUpdate={updateClient} onMessage={goToMessages} onBack={()=>setView("list")}/>
        )}

        {/* Calendar */}
        {nav==="calendar"&&(
          <CalendarPanel clients={visibleClients} calEvents={calEvents} setCalEvents={setCalEvents}/>
        )}

        {nav==="messages"&&(
          <div>
            <div style={{marginBottom:20}}><div style={{fontFamily:"Bebas Neue",fontSize:28,letterSpacing:2,color:T.text}}>DIRECT MESSAGING</div><div style={{fontFamily:"DM Sans",fontSize:13,color:T.muted,marginTop:4}}>Real-time communication with all your athletes</div></div>
            <MessagingPanel clients={visibleClients} allMessages={allMessages} setAllMessages={setAllMessages}/>
          </div>
        )}
        {nav==="content"&&<ContentPanel clients={visibleClients}/>}
      </div>
    </div>
  );
}
